mapper.select:
SELECT *
FROM certificate_issue_rule
WHERE id = #{id}
  AND teacher_id = #{teacherId}
LIMIT 1

mapper.update:
UPDATE certificate_issue_rule
SET enabled = 0,
    updated_time = #{updatedTime}
WHERE course_id = #{courseId}
  AND enabled = 1

    AND id != #{excludeId}

mapper.delete:
DELETE FROM certificate_issue_rule
WHERE id = #{id}
  AND teacher_id = #{teacherId}
